    19‚Üí// Since Rust no longer uses jemalloc by default, ripgrep will, by default,
    20‚Üí// use the system allocator. On Linux, this would normally be glibc's
    21‚Üí// allocator, which is pretty good. In particular, ripgrep does not have a
    22‚Üí// particularly allocation heavy workload, so there really isn't much
    23‚Üí// difference (for ripgrep's purposes) between glibc's allocator and jemalloc.
    24‚Üí//
    25‚Üí// However, when ripgrep is built with musl, this means ripgrep will use musl's
    26‚Üí// allocator, which appears to be substantially worse. (musl's goal is not to
    27‚Üí// have the fastest version of everything. Its goal is to be small and amenable
    28‚Üí// to static compilation.) Even though ripgrep isn't particularly allocation
    29‚Üí// heavy, musl's allocator appears to slow down ripgrep quite a bit. Therefore,
    30‚Üí// when building with musl, we use jemalloc.
    31‚Üí//
    32‚Üí// We don't unconditionally use jemalloc because it can be nice to use the
    33‚Üí// system's default allocator by default. Moreover, jemalloc seems to increase
    34‚Üí// compilation times by a bit.
    35‚Üí//
    36‚Üí// Moreover, we only do this on 64-bit systems since jemalloc doesn't support
    37‚Üí// i686.
    38‚Üí#[cfg(all(target_env = "musl", target_pointer_width = "64"))]
    39‚Üí#[global_allocator]
    40‚Üístatic ALLOC: tikv_jemallocator::Jemalloc = tikv_jemallocator::Jemalloc;
    41‚Üí
    42‚Üí/// Then, as it was, then again it will be.
    43‚Üífn main() -> ExitCode {
    44‚Üí    match run(flags::parse()) {
    45‚Üí        Ok(code) => code,
    46‚Üí        Err(err) => {
    47‚Üí            // Look for a broken pipe error. In this case, we generally want
    48‚Üí            // to exit "gracefully" with a success exit code. This matches
    49‚Üí            // existing Unix convention. We need to handle this explicitly
    50‚Üí            // since the Rust runtime doesn't ask for PIPE signals, and thus
    51‚Üí            // we get an I/O error instead. Traditional C Unix applications
    52‚Üí            // quit by getting a PIPE signal that they don't handle, and thus
    53‚Üí            // the unhandled signal causes the process to unceremoniously
    54‚Üí            // terminate.
    55‚Üí            for cause in err.chain() {
    56‚Üí                if let Some(ioerr) = cause.downcast_ref::<std::io::Error>() {
    57‚Üí                    if ioerr.kind() == std::io::ErrorKind::BrokenPipe {
    58‚Üí                        return ExitCode::from(0);
    59‚Üí                    }
    60‚Üí                }
    61‚Üí            }
    62‚Üí            eprintln_locked!("{:#}", err);
    63‚Üí            ExitCode::from(2)
    64‚Üí        }
    65‚Üí    }
    66‚Üí}
