    68‚Üí/// The main entry point for ripgrep.
    69‚Üí///
    70‚Üí/// The given parse result determines ripgrep's behavior. The parse
    71‚Üí/// result should be the result of parsing CLI arguments in a low level
    72‚Üí/// representation, and then followed by an attempt to convert them into a
    73‚Üí/// higher level representation. The higher level representation has some nicer
    74‚Üí/// abstractions, for example, instead of representing the `-g/--glob` flag
    75‚Üí/// as a `Vec<String>` (as in the low level representation), the globs are
    76‚Üí/// converted into a single matcher.
    77‚Üífn run(result: crate::flags::ParseResult<HiArgs>) -> anyhow::Result<ExitCode> {
    78‚Üí    use crate::flags::{Mode, ParseResult};
    79‚Üí
    80‚Üí    let args = match result {
    81‚Üí        ParseResult::Err(err) => return Err(err),
    82‚Üí        ParseResult::Special(mode) => return special(mode),
    83‚Üí        ParseResult::Ok(args) => args,
    84‚Üí    };
    85‚Üí    let matched = match args.mode() {
    86‚Üí        Mode::Search(_) if !args.matches_possible() => false,
    87‚Üí        Mode::Search(mode) if args.threads() == 1 => search(&args, mode)?,
    88‚Üí        Mode::Search(mode) => search_parallel(&args, mode)?,
    89‚Üí        Mode::Files if args.threads() == 1 => files(&args)?,
    90‚Üí        Mode::Files => files_parallel(&args)?,
    91‚Üí        Mode::Types => return types(&args),
    92‚Üí        Mode::Generate(mode) => return generate(mode),
    93‚Üí    };
    94‚Üí    Ok(if matched && (args.quiet() || !messages::errored()) {
    95‚Üí        ExitCode::from(0)
    96‚Üí    } else if messages::errored() {
    97‚Üí        ExitCode::from(2)
    98‚Üí    } else {
    99‚Üí        ExitCode::from(1)
   100‚Üí    })
   101‚Üí}
