   103‚Üí/// The top-level entry point for single-threaded search.
   104‚Üí///
   105‚Üí/// This recursively steps through the file list (current directory by default)
   106‚Üí/// and searches each file sequentially.
   107‚Üífn search(args: &HiArgs, mode: SearchMode) -> anyhow::Result<bool> {
   108‚Üí    let started_at = std::time::Instant::now();
   109‚Üí    let haystack_builder = args.haystack_builder();
   110‚Üí    let unsorted = args
   111‚Üí        .walk_builder()?
   112‚Üí        .build()
   113‚Üí        .filter_map(|result| haystack_builder.build_from_result(result));
   114‚Üí    let haystacks = args.sort(unsorted);
   115‚Üí
   116‚Üí    let mut matched = false;
   117‚Üí    let mut searched = false;
   118‚Üí    let mut stats = args.stats();
   119‚Üí    let mut searcher = args.search_worker(
   120‚Üí        args.matcher()?,
   121‚Üí        args.searcher()?,
   122‚Üí        args.printer(mode, args.stdout()),
   123‚Üí    )?;
   124‚Üí    for haystack in haystacks {
   125‚Üí        searched = true;
   126‚Üí        let search_result = match searcher.search(&haystack) {
   127‚Üí            Ok(search_result) => search_result,
   128‚Üí            // A broken pipe means graceful termination.
   129‚Üí            Err(err) if err.kind() == std::io::ErrorKind::BrokenPipe => break,
   130‚Üí            Err(err) => {
   131‚Üí                err_message!("{}: {}", haystack.path().display(), err);
   132‚Üí                continue;
   133‚Üí            }
   134‚Üí        };
   135‚Üí        matched = matched || search_result.has_match();
   136‚Üí        if let Some(ref mut stats) = stats {
   137‚Üí            *stats += search_result.stats().unwrap();
   138‚Üí        }
   139‚Üí        if matched && args.quit_after_match() {
   140‚Üí            break;
   141‚Üí        }
   142‚Üí    }
   143‚Üí    if args.has_implicit_path() && !searched {
   144‚Üí        eprint_nothing_searched();
   145‚Üí    }
   146‚Üí    if let Some(ref stats) = stats {
   147‚Üí        let wtr = searcher.printer().get_mut();
   148‚Üí        let _ = print_stats(mode, stats, started_at, wtr);
   149‚Üí    }
   150‚Üí    Ok(matched)
   151‚Üí}
