   153‚Üí/// The top-level entry point for multi-threaded search.
   154‚Üí///
   155‚Üí/// The parallelism is itself achieved by the recursive directory traversal.
   156‚Üí/// All we need to do is feed it a worker for performing a search on each file.
   157‚Üí///
   158‚Üí/// Requesting a sorted output from ripgrep (such as with `--sort path`) will
   159‚Üí/// automatically disable parallelism and hence sorting is not handled here.
   160‚Üífn search_parallel(args: &HiArgs, mode: SearchMode) -> anyhow::Result<bool> {
   161‚Üí    use std::sync::atomic::{AtomicBool, Ordering};
   162‚Üí
   163‚Üí    let started_at = std::time::Instant::now();
   164‚Üí    let haystack_builder = args.haystack_builder();
   165‚Üí    let bufwtr = args.buffer_writer();
   166‚Üí    let stats = args.stats().map(std::sync::Mutex::new);
   167‚Üí    let matched = AtomicBool::new(false);
   168‚Üí    let searched = AtomicBool::new(false);
   169‚Üí
   170‚Üí    let mut searcher = args.search_worker(
   171‚Üí        args.matcher()?,
   172‚Üí        args.searcher()?,
   173‚Üí        args.printer(mode, bufwtr.buffer()),
   174‚Üí    )?;
   175‚Üí    args.walk_builder()?.build_parallel().run(|| {
   176‚Üí        let bufwtr = &bufwtr;
   177‚Üí        let stats = &stats;
   178‚Üí        let matched = &matched;
   179‚Üí        let searched = &searched;
   180‚Üí        let haystack_builder = &haystack_builder;
   181‚Üí        let mut searcher = searcher.clone();
   182‚Üí
   183‚Üí        Box::new(move |result| {
   184‚Üí            let haystack = match haystack_builder.build_from_result(result) {
   185‚Üí                Some(haystack) => haystack,
   186‚Üí                None => return WalkState::Continue,
   187‚Üí            };
   188‚Üí            searched.store(true, Ordering::SeqCst);
   189‚Üí            searcher.printer().get_mut().clear();
   190‚Üí            let search_result = match searcher.search(&haystack) {
   191‚Üí                Ok(search_result) => search_result,
   192‚Üí                Err(err) => {
   193‚Üí                    err_message!("{}: {}", haystack.path().display(), err);
   194‚Üí                    return WalkState::Continue;
   195‚Üí                }
   196‚Üí            };
   197‚Üí            if search_result.has_match() {
   198‚Üí                matched.store(true, Ordering::SeqCst);
   199‚Üí            }
   200‚Üí            if let Some(ref locked_stats) = *stats {
   201‚Üí                let mut stats = locked_stats.lock().unwrap();
   202‚Üí                *stats += search_result.stats().unwrap();
   203‚Üí            }
   204‚Üí            if let Err(err) = bufwtr.print(searcher.printer().get_mut()) {
   205‚Üí                // A broken pipe means graceful termination.
   206‚Üí                if err.kind() == std::io::ErrorKind::BrokenPipe {
   207‚Üí                    return WalkState::Quit;
   208‚Üí                }
   209‚Üí                // Otherwise, we continue on our merry way.
   210‚Üí                err_message!("{}: {}", haystack.path().display(), err);
   211‚Üí            }
   212‚Üí            if matched.load(Ordering::SeqCst) && args.quit_after_match() {
   213‚Üí                WalkState::Quit
   214‚Üí            } else {
   215‚Üí                WalkState::Continue
   216‚Üí            }
   217‚Üí        })
   218‚Üí    });
   219‚Üí    if args.has_implicit_path() && !searched.load(Ordering::SeqCst) {
   220‚Üí        eprint_nothing_searched();
   221‚Üí    }
   222‚Üí    if let Some(ref locked_stats) = stats {
   223‚Üí        let stats = locked_stats.lock().unwrap();
   224‚Üí        let mut wtr = searcher.printer().get_mut();
   225‚Üí        let _ = print_stats(mode, &stats, started_at, &mut wtr);
   226‚Üí        let _ = bufwtr.print(&mut wtr);
   227‚Üí    }
   228‚Üí    Ok(matched.load(Ordering::SeqCst))
   229‚Üí}
