   231‚Üí/// The top-level entry point for file listing without searching.
   232‚Üí///
   233‚Üí/// This recursively steps through the file list (current directory by default)
   234‚Üí/// and prints each path sequentially using a single thread.
   235‚Üífn files(args: &HiArgs) -> anyhow::Result<bool> {
   236‚Üí    let haystack_builder = args.haystack_builder();
   237‚Üí    let unsorted = args
   238‚Üí        .walk_builder()?
   239‚Üí        .build()
   240‚Üí        .filter_map(|result| haystack_builder.build_from_result(result));
   241‚Üí    let haystacks = args.sort(unsorted);
   242‚Üí
   243‚Üí    let mut matched = false;
   244‚Üí    let mut path_printer = args.path_printer_builder().build(args.stdout());
   245‚Üí    for haystack in haystacks {
   246‚Üí        matched = true;
   247‚Üí        if args.quit_after_match() {
   248‚Üí            break;
   249‚Üí        }
   250‚Üí        if let Err(err) = path_printer.write(haystack.path()) {
   251‚Üí            // A broken pipe means graceful termination.
   252‚Üí            if err.kind() == std::io::ErrorKind::BrokenPipe {
   253‚Üí                break;
   254‚Üí            }
   255‚Üí            // Otherwise, we have some other error that's preventing us from
   256‚Üí            // writing to stdout, so we should bubble it up.
   257‚Üí            return Err(err.into());
   258‚Üí        }
   259‚Üí    }
   260‚Üí    Ok(matched)
   261‚Üí}
   262‚Üí
   263‚Üí/// The top-level entry point for multi-threaded file listing without
   264‚Üí/// searching.
   265‚Üí///
   266‚Üí/// This recursively steps through the file list (current directory by default)
   267‚Üí/// and prints each path sequentially using multiple threads.
   268‚Üí///
   269‚Üí/// Requesting a sorted output from ripgrep (such as with `--sort path`) will
   270‚Üí/// automatically disable parallelism and hence sorting is not handled here.
   271‚Üífn files_parallel(args: &HiArgs) -> anyhow::Result<bool> {
   272‚Üí    use std::{
   273‚Üí        sync::{
   274‚Üí            atomic::{AtomicBool, Ordering},
   275‚Üí            mpsc,
   276‚Üí        },
   277‚Üí        thread,
   278‚Üí    };
   279‚Üí
   280‚Üí    let haystack_builder = args.haystack_builder();
   281‚Üí    let mut path_printer = args.path_printer_builder().build(args.stdout());
   282‚Üí    let matched = AtomicBool::new(false);
   283‚Üí    let (tx, rx) = mpsc::channel::<crate::haystack::Haystack>();
   284‚Üí
   285‚Üí    // We spawn a single printing thread to make sure we don't tear writes.
   286‚Üí    // We use a channel here under the presumption that it's probably faster
   287‚Üí    // than using a mutex in the worker threads below, but this has never been
   288‚Üí    // seriously litigated.
   289‚Üí    let print_thread = thread::spawn(move || -> std::io::Result<()> {
   290‚Üí        for haystack in rx.iter() {
   291‚Üí            path_printer.write(haystack.path())?;
   292‚Üí        }
   293‚Üí        Ok(())
   294‚Üí    });
   295‚Üí    args.walk_builder()?.build_parallel().run(|| {
   296‚Üí        let haystack_builder = &haystack_builder;
   297‚Üí        let matched = &matched;
   298‚Üí        let tx = tx.clone();
   299‚Üí
   300‚Üí        Box::new(move |result| {
   301‚Üí            let haystack = match haystack_builder.build_from_result(result) {
   302‚Üí                Some(haystack) => haystack,
   303‚Üí                None => return WalkState::Continue,
   304‚Üí            };
   305‚Üí            matched.store(true, Ordering::SeqCst);
   306‚Üí            if args.quit_after_match() {
   307‚Üí                WalkState::Quit
   308‚Üí            } else {
   309‚Üí                match tx.send(haystack) {
   310‚Üí                    Ok(_) => WalkState::Continue,
   311‚Üí                    Err(_) => WalkState::Quit,
   312‚Üí                }
   313‚Üí            }
   314‚Üí        })
   315‚Üí    });
   316‚Üí    drop(tx);
   317‚Üí    if let Err(err) = print_thread.join().unwrap() {
   318‚Üí        // A broken pipe means graceful termination, so fall through.
   319‚Üí        // Otherwise, something bad happened while writing to stdout, so bubble
   320‚Üí        // it up.
   321‚Üí        if err.kind() != std::io::ErrorKind::BrokenPipe {
   322‚Üí            return Err(err.into());
   323‚Üí        }
   324‚Üí    }
   325‚Üí    Ok(matched.load(Ordering::SeqCst))
   326‚Üí}
