   328‚Üí/// The top-level entry point for `--type-list`.
   329‚Üífn types(args: &HiArgs) -> anyhow::Result<ExitCode> {
   330‚Üí    let mut count = 0;
   331‚Üí    let mut stdout = args.stdout();
   332‚Üí    for def in args.types().definitions() {
   333‚Üí        count += 1;
   334‚Üí        stdout.write_all(def.name().as_bytes())?;
   335‚Üí        stdout.write_all(b": ")?;
   336‚Üí
   337‚Üí        let mut first = true;
   338‚Üí        for glob in def.globs() {
   339‚Üí            if !first {
   340‚Üí                stdout.write_all(b", ")?;
   341‚Üí            }
   342‚Üí            stdout.write_all(glob.as_bytes())?;
   343‚Üí            first = false;
   344‚Üí        }
   345‚Üí        stdout.write_all(b"\n")?;
   346‚Üí    }
   347‚Üí    Ok(ExitCode::from(if count == 0 { 1 } else { 0 }))
   348‚Üí}
