   350‚Üí/// Implements ripgrep's "generate" modes.
   351‚Üí///
   352‚Üí/// These modes correspond to generating some kind of ancillary data related
   353‚Üí/// to ripgrep. At present, this includes ripgrep's man page (in roff format)
   354‚Üí/// and supported shell completions.
   355‚Üífn generate(mode: crate::flags::GenerateMode) -> anyhow::Result<ExitCode> {
   356‚Üí    use crate::flags::GenerateMode;
   357‚Üí
   358‚Üí    let output = match mode {
   359‚Üí        GenerateMode::Man => flags::generate_man_page(),
   360‚Üí        GenerateMode::CompleteBash => flags::generate_complete_bash(),
   361‚Üí        GenerateMode::CompleteZsh => flags::generate_complete_zsh(),
   362‚Üí        GenerateMode::CompleteFish => flags::generate_complete_fish(),
   363‚Üí        GenerateMode::CompletePowerShell => {
   364‚Üí            flags::generate_complete_powershell()
   365‚Üí        }
   366‚Üí    };
   367‚Üí    writeln!(std::io::stdout(), "{}", output.trim_end())?;
   368‚Üí    Ok(ExitCode::from(0))
   369‚Üí}
   370‚Üí
   371‚Üí/// Implements ripgrep's "special" modes.
   372‚Üí///
   373‚Üí/// A special mode is one that generally short-circuits most (not all) of
   374‚Üí/// ripgrep's initialization logic and skips right to this routine. The
   375‚Üí/// special modes essentially consist of printing help and version output. The
   376‚Üí/// idea behind the short circuiting is to ensure there is as little as possible
   377‚Üí/// (within reason) that would prevent ripgrep from emitting help output.
   378‚Üí///
   379‚Üí/// For example, part of the initialization logic that is skipped (among
   380‚Üí/// other things) is accessing the current working directory. If that fails,
   381‚Üí/// ripgrep emits an error. We don't want to emit an error if it fails and
   382‚Üí/// the user requested version or help information.
   383‚Üífn special(mode: crate::flags::SpecialMode) -> anyhow::Result<ExitCode> {
   384‚Üí    use crate::flags::SpecialMode;
   385‚Üí
   386‚Üí    let mut exit = ExitCode::from(0);
   387‚Üí    let output = match mode {
   388‚Üí        SpecialMode::HelpShort => flags::generate_help_short(),
   389‚Üí        SpecialMode::HelpLong => flags::generate_help_long(),
   390‚Üí        SpecialMode::VersionShort => flags::generate_version_short(),
   391‚Üí        SpecialMode::VersionLong => flags::generate_version_long(),
   392‚Üí        // --pcre2-version is a little special because it emits an error
   393‚Üí        // exit code if this build of ripgrep doesn't support PCRE2.
   394‚Üí        SpecialMode::VersionPCRE2 => {
   395‚Üí            let (output, available) = flags::generate_version_pcre2();
   396‚Üí            if !available {
   397‚Üí                exit = ExitCode::from(1);
   398‚Üí            }
   399‚Üí            output
   400‚Üí        }
   401‚Üí    };
   402‚Üí    writeln!(std::io::stdout(), "{}", output.trim_end())?;
   403‚Üí    Ok(exit)
   404‚Üí}
