    96‚Üí        if let Some(ref prog) = cmd {
    97‚Üí            let bin = grep::cli::resolve_binary(prog)?;
    98‚Üí            self.config.preprocessor = Some(bin);
    99‚Üí        } else {
   100‚Üí            self.config.preprocessor = None;
   101‚Üí        }
   102‚Üí        Ok(self)
   103‚Üí    }
   104‚Üí
   105‚Üí    /// Set the globs for determining which files should be run through the
   106‚Üí    /// preprocessor. By default, with no globs and a preprocessor specified,
   107‚Üí    /// every file is run through the preprocessor.
   108‚Üí    pub(crate) fn preprocessor_globs(
   109‚Üí        &mut self,
   110‚Üí        globs: ignore::overrides::Override,
   111‚Üí    ) -> &mut SearchWorkerBuilder {
   112‚Üí        self.config.preprocessor_globs = globs;
   113‚Üí        self
   114‚Üí    }
   115‚Üí
   116‚Üí    /// Enable the decompression and searching of common compressed files.
   117‚Üí    ///
   118‚Üí    /// When enabled, if a particular file path is recognized as a compressed
   119‚Üí    /// file, then it is decompressed before searching.
   120‚Üí    ///
   121‚Üí    /// Note that if a preprocessor command is set, then it overrides this
   122‚Üí    /// setting.
   123‚Üí    pub(crate) fn search_zip(
   124‚Üí        &mut self,
   125‚Üí        yes: bool,
   126‚Üí    ) -> &mut SearchWorkerBuilder {
   127‚Üí        self.config.search_zip = yes;
   128‚Üí        self
   129‚Üí    }
   130‚Üí
   131‚Üí    /// Set the binary detection that should be used when searching files
   132‚Üí    /// found via a recursive directory search.
   133‚Üí    ///
   134‚Üí    /// Generally, this binary detection may be
   135‚Üí    /// `grep::searcher::BinaryDetection::quit` if we want to skip binary files
   136‚Üí    /// completely.
   137‚Üí    ///
   138‚Üí    /// By default, no binary detection is performed.
   139‚Üí    pub(crate) fn binary_detection_implicit(
   140‚Üí        &mut self,
   141‚Üí        detection: grep::searcher::BinaryDetection,
   142‚Üí    ) -> &mut SearchWorkerBuilder {
   143‚Üí        self.config.binary_implicit = detection;
   144‚Üí        self
   145‚Üí    }
   146‚Üí
   147‚Üí    /// Set the binary detection that should be used when searching files
   148‚Üí    /// explicitly supplied by an end user.
   149‚Üí    ///
   150‚Üí    /// Generally, this binary detection should NOT be
   151‚Üí    /// `grep::searcher::BinaryDetection::quit`, since we never want to
   152‚Üí    /// automatically filter files supplied by the end user.
   153‚Üí    ///
   154‚Üí    /// By default, no binary detection is performed.
   155‚Üí    pub(crate) fn binary_detection_explicit(
   156‚Üí        &mut self,
   157‚Üí        detection: grep::searcher::BinaryDetection,
   158‚Üí    ) -> &mut SearchWorkerBuilder {
   159‚Üí        self.config.binary_explicit = detection;
   160‚Üí        self
   161‚Üí    }
   162‚Üí}
   163‚Üí
   164‚Üí/// The result of executing a search.
   165‚Üí///
   166‚Üí/// Generally speaking, the "result" of a search is sent to a printer, which
   167‚Üí/// writes results to an underlying writer such as stdout or a file. However,
   168‚Üí/// every search also has some aggregate statistics or meta data that may be
   169‚Üí/// useful to higher level routines.
   170‚Üí#[derive(Clone, Debug, Default)]
   171‚Üípub(crate) struct SearchResult {
   172‚Üí    has_match: bool,
   173‚Üí    stats: Option<grep::printer::Stats>,
   174‚Üí}
   175‚Üí
   176‚Üíimpl SearchResult {
   177‚Üí    /// Whether the search found a match or not.
   178‚Üí    pub(crate) fn has_match(&self) -> bool {
   179‚Üí        self.has_match
   180‚Üí    }
   181‚Üí
   182‚Üí    /// Return aggregate search statistics for a single search, if available.
   183‚Üí    ///
   184‚Üí    /// It can be expensive to compute statistics, so these are only present
   185‚Üí    /// if explicitly enabled in the printer provided by the caller.
   186‚Üí    pub(crate) fn stats(&self) -> Option<&grep::printer::Stats> {
   187‚Üí        self.stats.as_ref()
   188‚Üí    }
   189‚Üí}
   190‚Üí
   191‚Üí/// The pattern matcher used by a search worker.
   192‚Üí#[derive(Clone, Debug)]
   193‚Üípub(crate) enum PatternMatcher {
   194‚Üí    RustRegex(grep::regex::RegexMatcher),
   195‚Üí    #[cfg(feature = "pcre2")]
   196‚Üí    PCRE2(grep::pcre2::RegexMatcher),
   197‚Üí}
   198‚Üí
   199‚Üí/// The printer used by a search worker.
   200‚Üí///
   201‚Üí/// The `W` type parameter refers to the type of the underlying writer.
   202‚Üí#[derive(Clone, Debug)]
   203‚Üípub(crate) enum Printer<W> {
   204‚Üí    /// Use the standard printer, which supports the classic grep-like format.
   205‚Üí    Standard(grep::printer::Standard<W>),
   206‚Üí    /// Use the summary printer, which supports aggregate displays of search
   207‚Üí    /// results.
   208‚Üí    Summary(grep::printer::Summary<W>),
   209‚Üí    /// A JSON printer, which emits results in the JSON Lines format.
   210‚Üí    JSON(grep::printer::JSON<W>),
   211‚Üí}
   212‚Üí
   213‚Üíimpl<W: WriteColor> Printer<W> {
   214‚Üí    /// Return a mutable reference to the underlying printer's writer.
   215‚Üí    pub(crate) fn get_mut(&mut self) -> &mut W {
   216‚Üí        match *self {
   217‚Üí            Printer::Standard(ref mut p) => p.get_mut(),
   218‚Üí            Printer::Summary(ref mut p) => p.get_mut(),
   219‚Üí            Printer::JSON(ref mut p) => p.get_mut(),
   220‚Üí        }
   221‚Üí    }
   222‚Üí}
   223‚Üí
   224‚Üí/// A worker for executing searches.
   225‚Üí///
   226‚Üí/// It is intended for a single worker to execute many searches, and is
   227‚Üí/// generally intended to be used from a single thread. When searching using
   228‚Üí/// multiple threads, it is better to create a new worker for each thread.
   229‚Üí#[derive(Clone, Debug)]
   230‚Üípub(crate) struct SearchWorker<W> {
   231‚Üí    config: Config,
   232‚Üí    command_builder: grep::cli::CommandReaderBuilder,
   233‚Üí    /// This is `None` when `search_zip` is not enabled, since in this case it
   234‚Üí    /// can never be used. We do this because building the reader can sometimes
   235‚Üí    /// do non-trivial work (like resolving the paths of decompression binaries
   236‚Üí    /// on Windows).
   237‚Üí    decomp_builder: Option<grep::cli::DecompressionReaderBuilder>,
   238‚Üí    matcher: PatternMatcher,
   239‚Üí    searcher: grep::searcher::Searcher,
   240‚Üí    printer: Printer<W>,
   241‚Üí}
   242‚Üí
   243‚Üíimpl<W: WriteColor> SearchWorker<W> {
   244‚Üí    /// Execute a search over the given haystack.
   245‚Üí    pub(crate) fn search(
   246‚Üí        &mut self,
   247‚Üí        haystack: &crate::haystack::Haystack,
   248‚Üí    ) -> io::Result<SearchResult> {
   249‚Üí        let bin = if haystack.is_explicit() {
   250‚Üí            self.config.binary_explicit.clone()
   251‚Üí        } else {
   252‚Üí            self.config.binary_implicit.clone()
   253‚Üí        };
   254‚Üí        let path = haystack.path();
   255‚Üí        log::trace!("{}: binary detection: {:?}", path.display(), bin);
   256‚Üí
   257‚Üí        self.searcher.set_binary_detection(bin);
   258‚Üí        if haystack.is_stdin() {
   259‚Üí            self.search_reader(path, &mut io::stdin().lock())
   260‚Üí        } else if self.should_preprocess(path) {
   261‚Üí            self.search_preprocessor(path)
   262‚Üí        } else if self.should_decompress(path) {
   263‚Üí            self.search_decompress(path)
   264‚Üí        } else {
   265‚Üí            self.search_path(path)
   266‚Üí        }
   267‚Üí    }
   268‚Üí
   269‚Üí    /// Return a mutable reference to the underlying printer.
   270‚Üí    pub(crate) fn printer(&mut self) -> &mut Printer<W> {
   271‚Üí        &mut self.printer
   272‚Üí    }
   273‚Üí
   274‚Üí    /// Returns true if and only if the given file path should be
   275‚Üí    /// decompressed before searching.
   276‚Üí    fn should_decompress(&self, path: &Path) -> bool {
   277‚Üí        self.decomp_builder.as_ref().is_some_and(|decomp_builder| {
   278‚Üí            decomp_builder.get_matcher().has_command(path)
   279‚Üí        })
   280‚Üí    }
   281‚Üí
   282‚Üí    /// Returns true if and only if the given file path should be run through
   283‚Üí    /// the preprocessor.
   284‚Üí    fn should_preprocess(&self, path: &Path) -> bool {
   285‚Üí        if !self.config.preprocessor.is_some() {
   286‚Üí            return false;
   287‚Üí        }
   288‚Üí        if self.config.preprocessor_globs.is_empty() {
   289‚Üí            return true;
   290‚Üí        }
   291‚Üí        !self.config.preprocessor_globs.matched(path, false).is_ignore()
   292‚Üí    }
   293‚Üí
   294‚Üí    /// Search the given file path by first asking the preprocessor for the
   295‚Üí    /// data to search instead of opening the path directly.
   296‚Üí    fn search_preprocessor(
   297‚Üí        &mut self,
   298‚Üí        path: &Path,
   299‚Üí    ) -> io::Result<SearchResult> {
   300‚Üí        use std::{fs::File, process::Stdio};
   301‚Üí
   302‚Üí        let bin = self.config.preprocessor.as_ref().unwrap();
   303‚Üí        let mut cmd = std::process::Command::new(bin);
   304‚Üí        cmd.arg(path).stdin(Stdio::from(File::open(path)?));
   305‚Üí
   306‚Üí        let mut rdr = self.command_builder.build(&mut cmd).map_err(|err| {
   307‚Üí            io::Error::new(
   308‚Üí                io::ErrorKind::Other,
   309‚Üí                format!(
   310‚Üí                    "preprocessor command could not start: '{cmd:?}': {err}",
   311‚Üí                ),
   312‚Üí            )
   313‚Üí        })?;
   314‚Üí        let result = self.search_reader(path, &mut rdr).map_err(|err| {
   315‚Üí            io::Error::new(
   316‚Üí                io::ErrorKind::Other,
   317‚Üí                format!("preprocessor command failed: '{cmd:?}': {err}"),
   318‚Üí            )
   319‚Üí        });
   320‚Üí        let close_result = rdr.close();
   321‚Üí        let search_result = result?;
   322‚Üí        close_result?;
   323‚Üí        Ok(search_result)
   324‚Üí    }
   325‚Üí
   326‚Üí    /// Attempt to decompress the data at the given file path and search the
   327‚Üí    /// result. If the given file path isn't recognized as a compressed file,
   328‚Üí    /// then search it without doing any decompression.
   329‚Üí    fn search_decompress(&mut self, path: &Path) -> io::Result<SearchResult> {
   330‚Üí        let Some(ref decomp_builder) = self.decomp_builder else {
   331‚Üí            return self.search_path(path);
   332‚Üí        };
   333‚Üí        let mut rdr = decomp_builder.build(path)?;
   334‚Üí        let result = self.search_reader(path, &mut rdr);
   335‚Üí        let close_result = rdr.close();
   336‚Üí        let search_result = result?;
   337‚Üí        close_result?;
   338‚Üí        Ok(search_result)
   339‚Üí    }
   340‚Üí
   341‚Üí    /// Search the contents of the given file path.
   342‚Üí    fn search_path(&mut self, path: &Path) -> io::Result<SearchResult> {
   343‚Üí        use self::PatternMatcher::*;
   344‚Üí
   345‚Üí        let (searcher, printer) = (&mut self.searcher, &mut self.printer);
   346‚Üí        match self.matcher {
   347‚Üí            RustRegex(ref m) => search_path(m, searcher, printer, path),
   348‚Üí            #[cfg(feature = "pcre2")]
   349‚Üí            PCRE2(ref m) => search_path(m, searcher, printer, path),
   350‚Üí        }
   351‚Üí    }
   352‚Üí
   353‚Üí    /// Executes a search on the given reader, which may or may not correspond
   354‚Üí    /// directly to the contents of the given file path. Instead, the reader
   355‚Üí    /// may actually cause something else to be searched (for example, when
   356‚Üí    /// a preprocessor is set or when decompression is enabled). In those
   357‚Üí    /// cases, the file path is used for visual purposes only.
   358‚Üí    ///
   359‚Üí    /// Generally speaking, this method should only be used when there is no
   360‚Üí    /// other choice. Searching via `search_path` provides more opportunities
   361‚Üí    /// for optimizations (such as memory maps).
   362‚Üí    fn search_reader<R: io::Read>(
   363‚Üí        &mut self,
   364‚Üí        path: &Path,
   365‚Üí        rdr: &mut R,
   366‚Üí    ) -> io::Result<SearchResult> {
   367‚Üí        use self::PatternMatcher::*;
   368‚Üí
   369‚Üí        let (searcher, printer) = (&mut self.searcher, &mut self.printer);
   370‚Üí        match self.matcher {
   371‚Üí            RustRegex(ref m) => search_reader(m, searcher, printer, path, rdr),
   372‚Üí            #[cfg(feature = "pcre2")]
   373‚Üí            PCRE2(ref m) => search_reader(m, searcher, printer, path, rdr),
   374‚Üí        }
   375‚Üí    }
   376‚Üí}
   377‚Üí
   378‚Üí/// Search the contents of the given file path using the given matcher,
   379‚Üí/// searcher and printer.
   380‚Üífn search_path<M: Matcher, W: WriteColor>(
   381‚Üí    matcher: M,
   382‚Üí    searcher: &mut grep::searcher::Searcher,
   383‚Üí    printer: &mut Printer<W>,
   384‚Üí    path: &Path,
   385‚Üí) -> io::Result<SearchResult> {
   386‚Üí    match *printer {
   387‚Üí        Printer::Standard(ref mut p) => {
   388‚Üí            let mut sink = p.sink_with_path(&matcher, path);
   389‚Üí            searcher.search_path(&matcher, path, &mut sink)?;
   390‚Üí            Ok(SearchResult {
   391‚Üí                has_match: sink.has_match(),
   392‚Üí                stats: sink.stats().map(|s| s.clone()),
   393‚Üí            })
   394‚Üí        }
   395‚Üí        Printer::Summary(ref mut p) => {
   396‚Üí            let mut sink = p.sink_with_path(&matcher, path);
   397‚Üí            searcher.search_path(&matcher, path, &mut sink)?;
   398‚Üí            Ok(SearchResult {
   399‚Üí                has_match: sink.has_match(),
   400‚Üí                stats: sink.stats().map(|s| s.clone()),
   401‚Üí            })
   402‚Üí        }
   403‚Üí        Printer::JSON(ref mut p) => {
   404‚Üí            let mut sink = p.sink_with_path(&matcher, path);
   405‚Üí            searcher.search_path(&matcher, path, &mut sink)?;
   406‚Üí            Ok(SearchResult {
   407‚Üí                has_match: sink.has_match(),
   408‚Üí                stats: Some(sink.stats().clone()),
   409‚Üí            })
   410‚Üí        }
   411‚Üí    }
   412‚Üí}
   413‚Üí
   414‚Üí/// Search the contents of the given reader using the given matcher, searcher
   415‚Üí/// and printer.
   416‚Üífn search_reader<M: Matcher, R: io::Read, W: WriteColor>(
   417‚Üí    matcher: M,
   418‚Üí    searcher: &mut grep::searcher::Searcher,
   419‚Üí    printer: &mut Printer<W>,
   420‚Üí    path: &Path,
   421‚Üí    mut rdr: R,
   422‚Üí) -> io::Result<SearchResult> {
   423‚Üí    match *printer {
   424‚Üí        Printer::Standard(ref mut p) => {
   425‚Üí            let mut sink = p.sink_with_path(&matcher, path);
   426‚Üí            searcher.search_reader(&matcher, &mut rdr, &mut sink)?;
   427‚Üí            Ok(SearchResult {
   428‚Üí                has_match: sink.has_match(),
   429‚Üí                stats: sink.stats().map(|s| s.clone()),
   430‚Üí            })
   431‚Üí        }
   432‚Üí        Printer::Summary(ref mut p) => {
   433‚Üí            let mut sink = p.sink_with_path(&matcher, path);
   434‚Üí            searcher.search_reader(&matcher, &mut rdr, &mut sink)?;
   435‚Üí            Ok(SearchResult {
   436‚Üí                has_match: sink.has_match(),
   437‚Üí                stats: sink.stats().map(|s| s.clone()),
   438‚Üí            })
   439‚Üí        }
   440‚Üí        Printer::JSON(ref mut p) => {
   441‚Üí            let mut sink = p.sink_with_path(&matcher, path);
   442‚Üí            searcher.search_reader(&matcher, &mut rdr, &mut sink)?;
   443‚Üí            Ok(SearchResult {
   444‚Üí                has_match: sink.has_match(),
   445‚Üí                stats: Some(sink.stats().clone()),
   446‚Üí            })
   447‚Üí        }
   448‚Üí    }
   449‚Üí}
